#files-cont.preview-l .c2f-upload-thumb .ui.image { width: 190px; height: 190px; }
#files-cont.preview-l .c2f-upload-body { flex: 1; }

/* --- M: ~4 por linha, vertical, detalhes reduzidos (só tamanho) --- */
#files-cont.preview-m .c2f-upload-cel { width: calc(25% - 12px); }
#files-cont.preview-m .c2f-upload-thumb .ui.image { width: 100%; height: 160px; }
#files-cont.preview-m .c2f-upload-details tr:nth-child(1),
#files-cont.preview-m .c2f-upload-details tr:nth-child(3) { display: none; }
#files-cont.preview-m .c2f-upload-buttons .button { font-size: .85rem; }

/* --- S: ~6 por linha, mínimo: thumb + nome + botões (sem tabela de detalhes) --- */
#files-cont.preview-s .c2f-upload-cel { width: calc(16.66% - 12px); padding: 8px !important; }
#files-cont.preview-s .c2f-upload-thumb .ui.image { width: 100%; height: 100px; }
#files-cont.preview-s .c2f-upload-details { display: none; }
#files-cont.preview-s .c2f-upload-name { font-size: .82em; margin: 6px 0 2px; }
#files-cont.preview-s .c2f-upload-buttons .button { font-size: .72rem; padding: .5em .7em; margin: 0 1px 3px; }

/* Responsividade */
@media only screen and (max-width: 991px) {
    #files-cont.preview-m .c2f-upload-cel { width: calc(33.33% - 12px); }
    #files-cont.preview-s .c2f-upload-cel { width: calc(25% - 12px); }
}

@media only screen and (max-width: 767px) {
    #files-cont.preview-l .c2f-upload-cel,
    #files-cont.preview-xl .c2f-upload-cel { width: 100%; flex-direction: column; }
    #files-cont.preview-l .c2f-upload-thumb,
    #files-cont.preview-xl .c2f-upload-thumb { flex: none; }
    #files-cont.preview-l .c2f-upload-thumb .ui.image,
    #files-cont.preview-xl .c2f-upload-thumb .ui.image { width: 100%; height: auto; }
    #files-cont.preview-m .c2f-upload-cel,
    #files-cont.preview-s .c2f-upload-cel { width: calc(50% - 12px); }
}

